module accu
(
    input clk,
    input rst_n,
    input [7:0] data_in,
    input valid_in,
    output reg valid_out,
    output reg [9:0] data_out
);

reg [7:0] data_in_reg [3:0];
reg [9:0] data_out_reg;
reg [1:0] cnt;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        cnt <= 2'b00;
        valid_out <= 1'b0;
        data_out_reg <= 10'b0;
        data_in_reg[0] <= 8'b0;
        data_in_reg[1] <= 8'b0;
        data_in_reg[2] <= 8'b0;
        data_in_reg[3] <= 8'b0;
    end else begin
        if (valid_in) begin
            data_in_reg[cnt] <= data_in;
            cnt <= cnt + 2'b01;
            if (cnt == 2'b11) begin
                data_out_reg <= data_in_reg[0] + data_in_reg[1] + data_in_reg[2] + data_in_reg[3];
                valid_out <= 1'b1;
                cnt <= 2'b00;
            end else begin
                valid_out <= 1'b0;
            end
        end else begin
            valid_out <= 1'b0;
        end
    end
end

always @(posedge clk) begin
    data_out <= data_out_reg;
end

endmodule
